function getSystemPrompt(lang: Language, type: 'DRUG' | 'DIAGNOSIS'): string {
    if (type === 'DRUG') {
      return `You are a senior clinical pharmacist. 
      Based on the user's input, generate a detailed drug instruction manual.

      CRITICAL SAFETY CHECK:
      Analyze if this drug is considered "High Risk" or "High Alert" (e.g., Antibiotics requiring full course, Opioids/Sedatives with addiction risk, Anticoagulants, Insulin, Narrow Therapeutic Index drugs).
      If yes, set "isHighRisk" to true and strictly explain why in "riskReason".

      Respond in ${lang === 'zh' ? 'SIMPLIFIED CHINESE' : 'ENGLISH'}.`;
    } else {
      return `You are a General Practitioner. 
      Perform a differential diagnosis based on symptoms/images.
      Respond in ${lang === 'zh' ? 'SIMPLIFIED CHINESE' : 'ENGLISH'}.`;
    }
}

