          name: { type: Type.STRING },
          probability: { type: Type.STRING },
          explanation: { type: Type.STRING },
          medications: { type: Type.ARRAY, items: { type: Type.STRING } },
          treatments: { type: Type.ARRAY, items: { type: Type.STRING } },
        },
        required: ["name", "probability", "explanation", "medications", "treatments"],
      },
    },
    lifestyle_advice: { type: Type.STRING },
  },
  required: ["urgency", "urgency_reason", "summary", "potential_conditions", "lifestyle_advice"],
};

export const getDrugInfoFromText = async (query: string, lang: Language): Promise<DrugInfo> => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: lang === 'zh' ? `查询药品：${query}` : `Identify drug: ${query}`,
    config: {
      systemInstruction: getSystemPrompt(lang, 'DRUG'),
      responseMimeType: 'application/json',
      responseSchema: drugSchema,
    }
  });

  if (!response.text) throw new Error("No response from AI");
  return JSON.parse(response.text) as DrugInfo;
};

export const getDrugInfoFromImage = async (base64Image: string, lang: Language): Promise<DrugInfo> => {
  const match = base64Image.match(/^data:(.+);base64,(.+)$/);
  if (!match) throw new Error("Invalid image data");

  const mimeType = match[1];
  const data = match[2];

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: {
      parts: [
        { inlineData: { mimeType, data } },
        { text: lang === 'zh' ? "识别图中的药品" : "Identify the drug" }
      ]
    },
    config: {
      systemInstruction: getSystemPrompt(lang, 'DRUG'),
      responseMimeType: 'application/json',
      responseSchema: drugSchema,
    }
  });

  if (!response.text) throw new Error("No response from AI");
  return JSON.parse(response.text) as DrugInfo;
};

export const analyzeSymptoms = async (symptoms: string, base64Image: string | undefined, lang: Language): Promise<DiagnosisInfo> => {
  const parts: any[] = [];

  if (base64Image) {
    const match = base64Image.match(/^data:(.+);base64,(.+)$/);
    if (match) {
        parts.push({ inlineData: { mimeType: match[1], data: match[2] } });
    }
  }

  const symptomText = symptoms.trim() || (lang === 'zh' ? "无文字描述" : "No text description");
  parts.push({ text: lang === 'zh' ? `我的症状：${symptomText}` : `My symptoms: ${symptomText}` });

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: { parts },
    config: {
      systemInstruction: getSystemPrompt(lang, 'DIAGNOSIS'),
      responseMimeType: 'application/json',
      responseSchema: diagnosisSchema,
    }
  });

  if (!response.text) throw new Error("No response from AI");
  return JSON.parse(response.text) as DiagnosisInfo;
};

export const askFollowUpQuestion = async (context: string, question: string, lang: Language): Promise<string> => {
  const systemPrompt = lang === 'zh' 
    ? "你是一位友善、专业的医疗助手。请根据提供的上下文回答追问。回答要简洁（100字以内），安抚用户情绪。"
    : "You are a friendly, professional medical assistant. Answer based on context. Keep it concise (under 100 words) and reassuring.";

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Context:\n${context}\n\nQuestion: ${question}`,
    config: {
      systemInstruction: systemPrompt,
    }
  });

  return response.text || "";
};

import React, { useState, useRef, useCallback, useEffect } from 'react';
